import{_ as n,c as i,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Kompatibilität: Claude Code Skills | opencode-agent-skills","description":"Erfahren Sie, wie OpenCode Agent Skills mit Claude Code Skills und dem Plugin-System kompatibel sind. Beherrschen Sie den Mechanismus zur Tool-Zuordnung, die Priorität der Skill-Erkennung und die Wiederverwendung des Claude Skill-Ökosystems.","frontmatter":{"title":"Kompatibilität: Claude Code Skills | opencode-agent-skills","sidebarTitle":"Claude Skills wiederverwenden","subtitle":"Claude Code Skill-Kompatibilität","description":"Erfahren Sie, wie OpenCode Agent Skills mit Claude Code Skills und dem Plugin-System kompatibel sind. Beherrschen Sie den Mechanismus zur Tool-Zuordnung, die Priorität der Skill-Erkennung und die Wiederverwendung des Claude Skill-Ökosystems.","tags":["Kompatibilität","Claude Code","Skill-Wiederverwendung"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),s={name:"de/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function a(o,e,r,d,u,c){return l(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-skill-kompatibilitat" tabindex="-1">Claude Code Skill-Kompatibilität <a class="header-anchor" href="#claude-code-skill-kompatibilitat" aria-label="Permalink to &quot;Claude Code Skill-Kompatibilität&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Verstehen, wie Plugins automatisch mit dem Claude Code Skill-Format kompatibel sind</li><li>Den Mechanismus zur Tool-Zuordnung beherrschen, damit Claude Skills in OpenCode korrekt funktionieren</li><li>Die vollständigen Prioritätsregeln zur Skill-Erkennung verstehen</li><li>Vorhandene Skills aus dem Claude Plugin-Markt wiederverwenden, ohne sie neu schreiben zu müssen</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie haben bereits einige Claude Code Skills oder möchten Skills aus dem Claude Plugin-Markt verwenden, aber diese Skills wurden für Claude Code geschrieben. Die direkte Verwendung in OpenCode führt zu Problemen:</p><ul><li>Tool-Aufrufe in Claude Skills (z.B. <code>TodoWrite</code>, <code>Task</code>) existieren in OpenCode nicht</li><li>Es ist unklar, wie OpenCode installierte Claude Plugin Skills finden kann</li><li>Sorge, dass das Skill-Format inkompatibel ist und alles neu geschrieben werden muss</li></ul><h2 id="kerngedanke" tabindex="-1">Kerngedanke <a class="header-anchor" href="#kerngedanke" aria-label="Permalink to &quot;Kerngedanke&quot;">​</a></h2><p>Das OpenCode Agent Skills Plugin ermöglicht die nahtlose Verwendung von Claude Code Skills durch ein <strong>dreistufiges Kompatibilitätssystem</strong>, ohne Modifikationen:</p><ol><li><strong>Automatische Erkennung</strong> - Scannt Skills aus den Standard-Verzeichnissen von Claude Code (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Tool-Zuordnung</strong> - Lädt beim Laden eines Skills automatisch eine Tool-Zuordnungsanleitung ein, die Claude-Toolnamen in OpenCode-Toolnamen umwandelt</li><li><strong>Format-Unterstützung</strong> - Unterstützt gleichzeitig die v1- und v2-Installationsformate von Claude Plugins</li></ol><div class="info custom-block"><p class="custom-block-title">Wichtiges Konzept</p><p><strong>Claude Code Skill-Format</strong> - Die von Anthropic definierte Skill-Spezifikation, die <code>SKILL.md</code>-Dateien zur Beschreibung von Skills verwendet, einschließlich YAML-Frontmatter (Metadaten) und Markdown-Inhalt (Anweisungen).</p></div><h3 id="prinzip-der-tool-zuordnung" tabindex="-1">Prinzip der Tool-Zuordnung <a class="header-anchor" href="#prinzip-der-tool-zuordnung" aria-label="Permalink to &quot;Prinzip der Tool-Zuordnung&quot;">​</a></h3><p>Wenn das Plugin erkennt, dass ein für Claude Code geschriebenes Skill geladen wird, wird automatisch eine Tool-Zuordnungsanleitung injiziert:</p><table tabindex="0"><thead><tr><th>Claude Code Tool</th><th>OpenCode Tool</th><th>Zuordnungsregel</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>Kleinbuchstaben</td></tr><tr><td><code>Task</code> (Sub-Agent)</td><td><code>task</code> (mit subagent_type Parameter)</td><td>Parameter verwenden</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Toolname ersetzen</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>Kleinbuchstaben</td></tr></tbody></table><p><strong>Zuordnungsmethode</strong>: Das Plugin injiziert die Zuordnungsanleitung als XML in den Sitzungskontext beim Laden des Skills, und die KI ruft automatisch die richtigen Tools entsprechend der Zuordnung auf.</p><div class="tip custom-block"><p class="custom-block-title">Warum ist eine Zuordnung nötig?</p><p>Die Tool-Namenskonventionen von Claude Code und OpenCode unterscheiden sich. Claude verwendet PascalCase (z.B. <code>TodoWrite</code>), OpenCode verwendet Kleinbuchstaben (z.B. <code>todowrite</code>). Die Tool-Zuordnung ermöglicht es der KI zu wissen, wie Aufrufe umgewandelt werden müssen.</p></div><h3 id="prioritat-der-skill-erkennung" tabindex="-1">Priorität der Skill-Erkennung <a class="header-anchor" href="#prioritat-der-skill-erkennung" aria-label="Permalink to &quot;Priorität der Skill-Erkennung&quot;">​</a></h3><p>Das Plugin entdeckt Skills in folgender Reihenfolge, und <strong>die erste übereinstimmende Skill wird verwendet</strong> (Skills mit gleichem Namen werden nicht dupliziert):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Skill-Erkennungsablauf] --&gt; B[Projekt-Level OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Projekt-Level Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Benutzer-Level OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Benutzer-Level Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude Plugin-Cache]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude Plugin-Markt]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Prioritätsregeln</strong>:</p><ul><li>Projekt-Level Skills überschreiben Benutzer-Level Skills (für einfache Projekt-Anpassungen)</li><li>OpenCode Skills haben Vorrang vor Claude Skills (um Verwirrung zu vermeiden)</li><li>Skills mit gleichem Namen behalten nur die erste entdeckte Version bei</li></ul><details class="details custom-block"><summary>Beispiel: Überschreiben von Skills mit gleichem Namen</summary><p>Angenommen, Sie haben einen Skill namens <code>git-helper</code> an zwei Positionen:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (Claude Version)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (OpenCode Version)</li></ul><p><strong>Ergebnis</strong>: Die OpenCode Version wird verwendet (höhere Priorität)</p></details><h2 id="🎒-vorbereitung" tabindex="-1">🎒 Vorbereitung <a class="header-anchor" href="#🎒-vorbereitung" aria-label="Permalink to &quot;🎒 Vorbereitung&quot;">​</a></h2><ul><li>OpenCode Agent Skills Plugin ist installiert und konfiguriert</li><li>Grundlegendes Verständnis von Skills (empfohlen: zuerst <a href="./../../start/what-is-opencode-agent-skills/">Was ist OpenCode Agent Skills?</a> lesen)</li><li>(Optional) Bereits installierte Claude Code Plugins oder Skills</li></ul><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-uberprufen-ob-claude-skills-erkannt-werden" tabindex="-1">Schritt 1: Überprüfen, ob Claude Skills erkannt werden <a class="header-anchor" href="#schritt-1-uberprufen-ob-claude-skills-erkannt-werden" aria-label="Permalink to &quot;Schritt 1: Überprüfen, ob Claude Skills erkannt werden&quot;">​</a></h3><p><strong>Warum</strong> Sicherstellen, dass das Plugin Ihre Claude Code Skill-Verzeichnisse korrekt scannen kann.</p><p>Rufen Sie in OpenCode das Tool auf:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die zurückgegebene Skill-Liste enthält Skills aus <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, wobei das <code>source</code>-Feld der jeweiligen Skills die Quelle anzeigt (z.B. <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Kontrollpunkt ✅</strong>: Bestätigen Sie, dass die Liste die erwarteten Claude Skills enthält.</p><h3 id="schritt-2-einen-claude-skill-laden" tabindex="-1">Schritt 2: Einen Claude Skill laden <a class="header-anchor" href="#schritt-2-einen-claude-skill-laden" aria-label="Permalink to &quot;Schritt 2: Einen Claude Skill laden&quot;">​</a></h3><p><strong>Warum</strong> Überprüfen, ob der Tool-Zuordnungsmechanismus korrekt funktioniert.</p><p>Rufen Sie das Tool auf, um einen Claude Skill zu laden:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;dein-skill-name&quot;)</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Eine Erfolgsmeldung wird zurückgegeben, z.B. <code>Skill &quot;xxx&quot; loaded.</code>.</p><p><strong>Kontrollpunkt ✅</strong>: Die KI kann jetzt die Anweisungen des Skills verwenden.</p><h3 id="schritt-3-uberprufen-ob-die-tool-zuordnung-funktioniert" tabindex="-1">Schritt 3: Überprüfen, ob die Tool-Zuordnung funktioniert <a class="header-anchor" href="#schritt-3-uberprufen-ob-die-tool-zuordnung-funktioniert" aria-label="Permalink to &quot;Schritt 3: Überprüfen, ob die Tool-Zuordnung funktioniert&quot;">​</a></h3><p><strong>Warum</strong> Bestätigen, dass die KI korrekt OpenCode Tools statt Claude Tools aufrufen kann.</p><p>Stellen Sie der KI eine Aufgabe, die Tools des Skills erfordert, z.B.:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bitte verwenden Sie die Todo-Funktion im Skill, um mir eine Aufgabenliste zu erstellen.</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Die KI ruft korrekt OpenCodes <code>todowrite</code> Tool auf, nicht Claudes <code>TodoWrite</code> Tool.</p><div class="tip custom-block"><p class="custom-block-title">Wie verifiziert man, dass die Zuordnung funktioniert?</p><p>Überprüfen Sie die Tool-Aufruf-Logs der KI (wenn der Debug-Modus aktiviert ist). Sie werden sehen, dass <code>todowrite</code> anstelle von <code>TodoWrite</code> aufgerufen wird.</p></div><p><strong>Kontrollpunkt ✅</strong>: Tool-Aufruf erfolgreich, Aufgabe abgeschlossen.</p><h2 id="haufige-fehlerquellen" tabindex="-1">Häufige Fehlerquellen <a class="header-anchor" href="#haufige-fehlerquellen" aria-label="Permalink to &quot;Häufige Fehlerquellen&quot;">​</a></h2><h3 id="_1-inkompatible-plugin-formate" tabindex="-1">1. Inkompatible Plugin-Formate <a class="header-anchor" href="#_1-inkompatible-plugin-formate" aria-label="Permalink to &quot;1. Inkompatible Plugin-Formate&quot;">​</a></h3><p><strong>Problem</strong>: Alte Claude Plugins verwenden das v1-Format, neue das v2-Format, was dazu führt, dass einige Skills nicht erkannt werden.</p><p><strong>Ursache</strong>: Die Struktur von <code>installed_plugins.json</code> unterscheidet sich zwischen v1 und v2.</p><p><strong>Lösung</strong>: Das Plugin unterstützt beide Formate, keine manuelle Konvertierung erforderlich. Falls Skills dennoch nicht erkannt werden, überprüfen Sie, ob <code>~/.claude/plugins/installed_plugins.json</code> existiert und das richtige Format hat.</p><h3 id="_2-tool-zuordnung-nicht-aktiv" tabindex="-1">2. Tool-Zuordnung nicht aktiv <a class="header-anchor" href="#_2-tool-zuordnung-nicht-aktiv" aria-label="Permalink to &quot;2. Tool-Zuordnung nicht aktiv&quot;">​</a></h3><p><strong>Problem</strong>: Die KI ruft immer noch Claude-Toolnamen auf, was zu Fehlern führt.</p><p><strong>Ursache</strong>: Der Skill-Inhalt könnte die Tool-Zuordnungsanleitung umgangen haben oder verwendet hartkodierte Tool-Aufrufe.</p><p><strong>Lösung</strong>:</p><ul><li>Stellen Sie sicher, dass der Skill nach dem Laden verwendet wird, nicht direkte Tool-Aufrufe</li><li>Wenn der Skill Code-Beispiele enthält, ändern Sie die Toolnamen manuell in das OpenCode-Format</li></ul><h3 id="_3-namenskonflikte-bei-skills" tabindex="-1">3. Namenskonflikte bei Skills <a class="header-anchor" href="#_3-namenskonflikte-bei-skills" aria-label="Permalink to &quot;3. Namenskonflikte bei Skills&quot;">​</a></h3><p><strong>Problem</strong>: Skills mit gleichem Namen an verschiedenen Orten, es wird die falsche Version geladen.</p><p><strong>Ursache</strong>: Die Priorität der Skill-Erkennung führt zu Überschreibungen.</p><p><strong>Lösung</strong>:</p><ul><li>Überprüfen Sie das <code>source</code>-Feld des Skills, um die Quelle zu bestätigen</li><li>Verwenden Sie das Namespace-Format, um die Quelle explizit anzugeben: <code>use_skill(skill=&quot;user:skill-name&quot;)</code> oder <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>Namespace-Syntax</summary><p>Das Plugin unterstützt das Format <code>namespace:skill-name</code>:</p><ul><li><code>project:skill-name</code> - Projekt-Level OpenCode Skill</li><li><code>claude-project:skill-name</code> - Projekt-Level Claude Skill</li><li><code>user:skill-name</code> - Benutzer-Level OpenCode Skill</li><li><code>claude-user:skill-name</code> - Benutzer-Level Claude Skill</li><li><code>claude-plugins:skill-name</code> - Claude Plugin-Markt Skill</li></ul></details><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Das OpenCode Agent Skills Plugin ermöglicht die nahtlose Wiederverwendung von Claude Code Skills durch ein dreistufiges Kompatibilitätssystem:</p><ul><li><strong>Automatische Erkennung</strong> - Scannt Skills von 6 Positionen, abdeckend Projekt-Level, Benutzer-Level und Plugin-Level</li><li><strong>Tool-Zuordnung</strong> - Konvertiert automatisch Claude-Toolnamen in OpenCode-Toolnamen</li><li><strong>Format-Unterstützung</strong> - Unterstützt gleichzeitig v1- und v2-Claude-Plugin-Formate</li></ul><p>Keine Neuimplementierung von Skills erforderlich, einfach installieren und verwenden – das Plugin behandelt Kompatibilitätsprobleme automatisch.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../superpowers-integration/">Superpowers Workflow-Integration</a></strong> kennen.</p><p>Sie werden lernen:</p><ul><li>Wie man den Superpowers-Modus aktiviert</li><li>Automatische Erkennung und Ladung von Superpowers-Skills</li><li>Wie strikte Workflows die Entwicklungseffizienz steigern</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Position anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Tool-Zuordnungsdefinition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 Format-Typdefinitionen</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Plugin-Installationspfad-Extraktion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Plugin-Skill-Erkennung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Markt-Skill-Erkennung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Cache-Skill-Erkennung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Prioritätsliste der Skill-Erkennung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>Deduplizierungslogik für gleichnamige Skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>toolTranslation Import</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Tool-Zuordnungsinjektion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>toolTranslation</code>: XML-String der Tool-Zuordnungsanleitung, der beim Laden des Skills in den Sitzungskontext injiziert wird. Definiert in <code>src/claude.ts:19-25</code>, importiert in <code>src/tools.ts:15</code></li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: Extrahiert Plugin-Installationspfade aus v1/v2-Formaten</li><li><code>discoverSkillsFromPluginDir()</code>: Scannt das <code>skills/</code>-Unterverzeichnis des Plugin-Verzeichnisses</li><li><code>discoverMarketplaceSkills()</code>: Erkennt Skills aus <code>~/.claude/plugins/marketplaces/</code> (Priorität)</li><li><code>discoverPluginCacheSkills()</code>: Erkennt Skills aus <code>~/.claude/plugins/cache/</code> (Fallback)</li><li><code>findFile()</code>: Sucht rekursiv nach einem angegebenen Dateinamen (Hilfsfunktion)</li></ul><p><strong>Wichtige Abläufe</strong>:</p><ol><li>Bei Plugin-Initialisierung wird <code>discoverAllSkills()</code> aufgerufen → durchläuft 6 Erkennungspfade</li><li>Bei Erkennung von Claude Plugin Skills wird <code>discoverMarketplaceSkills()</code> oder <code>discoverPluginCacheSkills()</code> aufgerufen</li><li>Beim Laden des Skills fügt das <code>use_skill</code>-Tool <code>toolTranslation</code> in den XML-Inhalt ein (Zeile 244)</li></ol></details>`,68)])])}const g=n(s,[["render",a]]);export{k as __pageData,g as default};
